from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy import func
import os
import secrets

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///annotations.db'
app.config['SECRET_KEY'] = secrets.token_hex(16)
db = SQLAlchemy(app)

class Annotation(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    image_id = db.Column(db.String(80), nullable=False)
    label = db.Column(db.String(80), nullable=False)
    annotator_id = db.Column(db.String(80), nullable=False)

db.create_all()

def validate_input(data):
    if 'image_id' not in data or 'label' not in data or 'annotator_id' not in data:
        return False
    return True

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.json
    if not validate_input(data):
        return jsonify({'error': 'Invalid input'}), 400
    
    new_annotation = Annotation(
        image_id=data['image_id'],
        label=data['label'],
        annotator_id=data['annotator_id']
    )
    db.session.add(new_annotation)
    db.session.commit()
    return jsonify({'message': 'Annotation added'}), 201

@app.route('/aggregate/<image_id>', methods=['GET'])
def aggregate(image_id):
    labels = db.session.query(Annotation.label, func.count(Annotation.label)).filter(Annotation.image_id == image_id).group_by(Annotation.label).all()
    if not labels:
        return jsonify({'error': 'No annotations found'}), 404

    majority_label = max(labels, key=lambda x: x[1])[0]
    return jsonify({'image_id': image_id, 'majority_label': majority_label}), 200

if __name__ == '__main__':
    app.run(ssl_context='adhoc')